INSERT INTO `course_student_teacher_allocation` (student_id, course_id, teacher_id) SELECT S_Ranked.student_id, S_Ranked.course_id, T_Ranked.teacher_faculty_id FROM (     SELECT student_id, course_id,     ROW_NUMBER() OVER (PARTITION BY course_id ORDER BY student_id) as s_idx     FROM `student_courses` ) AS S_Ranked JOIN (     SELECT t.faculty_id AS teacher_faculty_id, tca.course_id,     ROW_NUMBER() OVER (PARTITION BY tca.course_id ORDER BY t.faculty_id) as t_idx,     COUNT(*) OVER (PARTITION BY tca.course_id) as t_total     FROM `teacher_course_allocation` tca     JOIN `teachers` t ON (tca.teacher_id = t.faculty_id OR CAST(tca.teacher_id AS CHAR) = CAST(t.id AS CHAR)) ) AS T_Ranked ON S_Ranked.course_id = T_Ranked.course_id WHERE T_Ranked.t_idx = ((S_Ranked.s_idx - 1) % T_Ranked.t_total) + 1;
